const body = $input.first().json.body;
const automations = body.automations;
const opportunity = body.opportunity;
const stageName = body.stage_name;
const pipelineName = body.pipeline_name;

const emails = [];

for (const rule of automations) {
  let toEmail = '';

  if (rule.email_to_type === 'candidate') {
    toEmail = opportunity.email || '';
  } else if (rule.email_to_type === 'contact') {
    toEmail = opportunity.email || '';
  } else if (rule.email_to_type === 'custom') {
    toEmail = rule.email_to || '';
  }

  // Variables replace karo
  let subject = rule.email_subject || '';
  let body = rule.email_body || '';

  subject = subject.replace('{{candidate_name}}', opportunity.contact_name || '');
  subject = subject.replace('{{stage_name}}', stageName || '');
  subject = subject.replace('{{pipeline_name}}', pipelineName || '');

  body = body.replace('{{candidate_name}}', opportunity.contact_name || '');
  body = body.replace('{{candidate_email}}', opportunity.email || '');
  body = body.replace('{{stage_name}}', stageName || '');
  body = body.replace('{{pipeline_name}}', pipelineName || '');

  if (toEmail) {
    emails.push({
      to: toEmail,
      cc: rule.email_cc || '',
      from: rule.smtp_from || '',
      subject: subject,
      body: body
    });
  }
}

return emails.map(e => ({ json: e }));
